#!/usr/bin/env python3
import json
import struct
import sys
import zlib


def paeth(a, b, c):
    p = a + b - c
    pa = abs(p - a)
    pb = abs(p - b)
    pc = abs(p - c)
    if pa <= pb and pa <= pc:
        return a
    if pb <= pc:
        return b
    return c


def decode_png(path):
    with open(path, "rb") as f:
        data = f.read()
    if data[:8] != b"\x89PNG\r\n\x1a\n":
        raise ValueError("not a png")

    pos = 8
    width = height = bit_depth = color_type = None
    compressed = bytearray()
    while pos < len(data):
        length = struct.unpack(">I", data[pos:pos + 4])[0]
        kind = data[pos + 4:pos + 8]
        chunk = data[pos + 8:pos + 8 + length]
        pos += 12 + length
        if kind == b"IHDR":
            width, height, bit_depth, color_type, comp, filt, interlace = struct.unpack(">IIBBBBB", chunk)
            if bit_depth != 8 or comp != 0 or filt != 0 or interlace != 0:
                raise ValueError("unsupported png")
        elif kind == b"IDAT":
            compressed.extend(chunk)
        elif kind == b"IEND":
            break

    channels_by_type = {0: 1, 2: 3, 4: 2, 6: 4}
    channels = channels_by_type.get(color_type)
    if channels is None:
        raise ValueError("unsupported png color type")

    raw = zlib.decompress(bytes(compressed))
    stride = width * channels
    rows = []
    prev = [0] * stride
    idx = 0
    for _ in range(height):
        filter_type = raw[idx]
        idx += 1
        scan = list(raw[idx:idx + stride])
        idx += stride
        recon = [0] * stride
        for i, val in enumerate(scan):
            left = recon[i - channels] if i >= channels else 0
            up = prev[i]
            up_left = prev[i - channels] if i >= channels else 0
            if filter_type == 0:
                recon[i] = val
            elif filter_type == 1:
                recon[i] = (val + left) & 255
            elif filter_type == 2:
                recon[i] = (val + up) & 255
            elif filter_type == 3:
                recon[i] = (val + ((left + up) // 2)) & 255
            elif filter_type == 4:
                recon[i] = (val + paeth(left, up, up_left)) & 255
            else:
                raise ValueError("bad png filter")
        rows.append(recon)
        prev = recon
    return width, height, channels, color_type, rows


def image_vector(path):
    width, height, channels, color_type, rows = decode_png(path)
    pixels = []
    for y in range(28):
        sy = min(height - 1, (y * height) // 28)
        row = rows[sy]
        for x in range(28):
            sx = min(width - 1, (x * width) // 28)
            i = sx * channels
            if color_type == 0:
                gray = row[i] / 255.0
            elif color_type == 2:
                gray = (0.299 * row[i] + 0.587 * row[i + 1] + 0.114 * row[i + 2]) / 255.0
            elif color_type == 4:
                gray = (row[i] / 255.0) * (row[i + 1] / 255.0)
            else:
                gray = ((0.299 * row[i] + 0.587 * row[i + 1] + 0.114 * row[i + 2]) / 255.0) * (row[i + 3] / 255.0)
            pixels.append(gray)
    return pixels


def tensor(weights, name):
    return weights["tensors"][name]["data"]


def linear_relu(x, w, b, in_dim, out_dim, relu):
    out = []
    for o in range(out_dim):
        row = o * in_dim
        value = b[o]
        for i, xv in enumerate(x):
            value += w[row + i] * xv
        out.append(max(0.0, value) if relu else value)
    return out


def main():
    if len(sys.argv) != 3:
        return 1
    with open(sys.argv[1], "r") as f:
        weights = json.load(f)

    x = image_vector(sys.argv[2])
    h1 = linear_relu(x, tensor(weights, "input_layer.weight"), tensor(weights, "input_layer.bias"), 784, 16, True)
    h2 = linear_relu(h1, tensor(weights, "hidden_layer.weight"), tensor(weights, "hidden_layer.bias"), 16, 16, True)
    y = linear_relu(h2, tensor(weights, "output_layer.weight"), tensor(weights, "output_layer.bias"), 16, 10, False)
    print(max(range(10), key=lambda i: y[i]))
    return 0


if __name__ == "__main__":
    try:
        raise SystemExit(main())
    except Exception:
        raise SystemExit(1)

